import React, { useState } from 'react';
import './App.css';
import Sidebar from './Sidebar';
import axios from 'axios';

function App() {
  const appURL="http://localhost:8080";
  const [translatedText,setTranslatedText]=useState("");
  function translateText(e){
    var text=e.target.value;
    axios.post(appURL+"/api/translate",{},{
      params:{
        text:text
      },
    }).then((result)=>{
      console.log(result.data);
      setTranslatedText(result.data);
    }).catch((e)=>{
      console.log(e);
    })
  }
  return (
    <div className="App" id="outer-container">
      <Sidebar pageWrapId={'page-wrap'} outerContainerId={'outer-container'} />
      <div id="page-wrap">
        <h1>Vocal Kord</h1>
        <h2>Translate to other languages at ease!</h2>
      </div>
      <div className='row'>
        <div className='col-lg-12'>
          <div className='card card-body'>
            <div className='row'>
              <div className='col-sm-4 mb-2 mt-2'>
               <textarea cols="80" rows="15" onChange={(e)=>translateText(e)} placeholder='Add text for translation'></textarea>
              </div>
              <div className='col-sm-2 mb-2 mt-2'>
                <a className='btn btn-primary'>Exchange</a>
              </div>
            <div className='col-sm-4 mb-2 mt-2'>
               <textarea cols="80" rows="15" placeholder='Translated text' value={translatedText}></textarea>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
